def build_list(arr):
    head = current = ListNode(0)
    for x in arr:
        current.next = ListNode(x)
        current = current.next
    return head.next

def list_to_array(node):
    arr = []
    while node:
        arr.append(node.val)
        node = node.next
    return arr

