# Helper to convert tree to level order list for printing
from collections import deque
def tree_to_level_order(root: Optional[TreeNode]) -> List[Optional[int]]:
    if not root:
        return []
    result = []
    q = deque([root])
    while q:
        node = q.popleft()
        if node:
            result.append(node.val)
            q.append(node.left)
            q.append(node.right)
        else:
            result.append(None)
    # Trim trailing nulls
    while result and result[-1] is None:
        result.pop()
    return result

