shortest-path-in-a-hidden-grid.starterCode:
class GridMaster:
    def __init__(self, grid, start_pos=(0,0)):
        self.grid = grid
        self.rows = len(grid)
        self.cols = len(grid[0])
        self.curr_r, self.curr_c = start_pos
        self.target_r, self.target_c = -1, -1
        for r in range(self.rows):
            for c in range(self.cols):
                if grid[r][c] == 1:
                    self.target_r, self.target_c = r, c
                    break
            if self.target_r != -1:
                break
    def canMove(self, direction: str) -> bool:
        nr, nc = self.curr_r, self.curr_c
        if direction == 'U': nr -= 1
        elif direction == 'D': nr += 1
        elif direction == 'L': nc -= 1
        elif direction == 'R': nc += 1
        if 0 <= nr < self.rows and 0 <= nc < self.cols and self.grid[nr][nc] != 2:
            return True
        return False
    def move(self, direction: str) -> int:
        if not self.canMove(direction):
            raise ValueError("Cannot move in this direction")
        if direction == 'U': self.curr_r -= 1
        elif direction == 'D': self.curr_r += 1
        elif direction == 'L': self.curr_c -= 1
        elif direction == 'R': self.curr_c += 1
        return self.grid[self.curr_r][self.curr_c]
    def isTarget(self) -> bool:
        return self.grid[self.curr_r][self.curr_c] == 1

class Solution:
    def findShortestPath(self, master: 'GridMaster') -> int:
        # Your code here
